import unittest
from invoice import total

class InvoiceTest(unittest.TestCase):
    def test_total(self):
        self.assertEqual(total(80, 20), 100)
        self.assertEqual(total(0, 0), 0)

if __name__ == '__main__':
    unittest.main()

