import unittest
from percent import bounded

class PercentTest(unittest.TestCase):
    def test_boundaries(self):
        self.assertEqual(bounded(-3), 0)
        self.assertEqual(bounded(40), 40)
        self.assertEqual(bounded(140), 100)

